section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/fast-vs-slow-burn-rule.json",
  "type": "object",
  "required": [
    "slo_id",
    "slo_target",
    "windows",
    "sli_recording_rule_prefix",
    "alertmanager_routes",
    "runbook_urls"
  ],
  "properties": {
    "slo_id": {
      "type": "string",
      "description": "string"
    },
    "slo_target": {
      "type": "number",
      "description": "number"
    },
    "windows": {
      "type": "array",
      "description": "array (exactly 4 entries: 1h, 6h, 3d, 30d with burn_rate_threshold + routing)"
    },
    "sli_recording_rule_prefix": {
      "type": "string",
      "description": "string"
    },
    "alertmanager_routes": {
      "type": "object",
      "description": "object {window: receiver}"
    },
    "runbook_urls": {
      "type": "object",
      "description": "object {window: url}"
    }
  }
}
